import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Header from './components/Header';
import Home from './pages/Home';
import Login from './pages/Login';
import Register from './pages/Register';
import Dashboard from './pages/Dashboard'; // Include the Dashboard import
import ComplaintForm from './components/ComplaintForm'; // Form to create complaints
import ComplaintList from './components/ComplaintList'; // List of complaints
import ComplaintDetailPage from './pages/ComplaintDetailPage'; // Detail view of a complaint
import './styles/style.css';

function App() {
  return (
    <Router>
      <Header />
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
        <Route path="/create-complaint" element={<ComplaintForm />} />
        <Route path="/complaints" element={<ComplaintList />} />
        <Route path="/complaints/:id" element={<ComplaintDetailPage />} />
        <Route path="/dashboard" element={<Dashboard />} /> {/* Add the Dashboard route */}
      </Routes>
    </Router>
  );
}

export default App;
